diff --git c/include/simdjson/dom/element-inl.h i/include/simdjson/dom/element-inl.h
index 1f071da608..d971e7a007 100644
--- c/include/simdjson/dom/element-inl.h
+++ i/include/simdjson/dom/element-inl.h
@@ -15,6 +15,24 @@

 namespace simdjson {

+namespace internal {
+
+simdjson_inline bool json_pointer_has_valid_syntax(std::string_view json_pointer) noexcept {
+  if (json_pointer.empty()) { return true; }
+  if (json_pointer[0] != '/') { return false; }
+  for (size_t i = 0; i < json_pointer.size(); i++) {
+    if (json_pointer[i] == '~') {
+      if (i + 1 >= json_pointer.size() || (json_pointer[i + 1] != '0' && json_pointer[i + 1] != '1')) {
+        return false;
+      }
+      i++;
+    }
+  }
+  return true;
+}
+
+} // namespace internal
+
 //
 // simdjson_result<dom::element> inline implementation
 //
@@ -383,8 +401,8 @@ inline simdjson_result<element> element::at_pointer(std::string_view json_pointe
     case internal::tape_type::START_ARRAY:
       return array(tape).at_pointer(json_pointer);
     default: {
-      if(!json_pointer.empty()) { // a non-empty string is invalid on an atom
-        return INVALID_JSON_POINTER;
+      if(!json_pointer.empty()) { // a non-empty string overshoots an atom if the pointer syntax is valid
+        return internal::json_pointer_has_valid_syntax(json_pointer) ? NO_SUCH_FIELD : INVALID_JSON_POINTER;
       }
       // an empty string means that we return the current node
       dom::element copy(*this);
